INSERT INTO environment_type (id, name, sunlight, ventilation, temperature, humidity, explanation) VALUES ('ENV-01', '햇빛이 풍부한 공간', '매우 높음'::sunlight_condition, '보통'::ventilation_condition, '보통~높음'::temperature_condition, '보통'::humidity_condition, '발코니나 남향 창가처럼 햇빛이 풍부하고 통풍이 잘 되는 공간입니다. 큰 식물이 잘 자라는 적극적인 환경입니다.');
INSERT INTO environment_type (id, name, sunlight, ventilation, temperature, humidity, explanation) VALUES ('ENV-02', '햇빛이 부족한 공간', '매우 낮음'::sunlight_condition, '보통'::ventilation_condition, '보통'::temperature_condition, '보통'::humidity_condition, '방안쪽이나 북향처럼 햇빛이 잘 들지 않는 공간입니다. 일부 식물에게는 오히려 좋은 환경입니다.');
INSERT INTO environment_type (id, name, sunlight, ventilation, temperature, humidity, explanation) VALUES ('ENV-03', '반음지 공간', '중간'::sunlight_condition, '보통'::ventilation_condition, '보통'::temperature_condition, '보통'::humidity_condition, '밝지만 직사광선이 직접 닿지 않는 공간입니다. 거실 안쪽이나 커튼 너머 빛이 들어오는 곳입니다.');
INSERT INTO environment_type (id, name, sunlight, ventilation, temperature, humidity, explanation) VALUES ('ENV-04', '온도가 높은 공간', '보통~높음'::sunlight_condition, '보통~낮음'::ventilation_condition, '높음'::temperature_condition, '보통~낮음'::humidity_condition, '온도가 높고 습도가 높은 공간입니다. 열대 식물에게 적합한 환경입니다.');
INSERT INTO environment_type (id, name, sunlight, ventilation, temperature, humidity, explanation) VALUES ('ENV-05', '온도가 낮은 공간', '보통'::sunlight_condition, '보통'::ventilation_condition, '낮음'::temperature_condition, '보통'::humidity_condition, '온도가 낮고 습도가 낮은 공간입니다. 일부 식물에게 손상이 올 수 있습니다.');
INSERT INTO environment_type (id, name, sunlight, ventilation, temperature, humidity, explanation) VALUES ('ENV-06', '건조한 공간', '보통'::sunlight_condition, '높음'::ventilation_condition, '보통'::temperature_condition, '낮음'::humidity_condition, '공기가 건조한 공간입니다. 건조에 잘 견디는 식물이 필요한 환경입니다.');
INSERT INTO environment_type (id, name, sunlight, ventilation, temperature, humidity, explanation) VALUES ('ENV-07', '습한 공간', '보통~낮음'::sunlight_condition, '낮음'::ventilation_condition, '보통'::temperature_condition, '높음'::humidity_condition, '습기가 많은 공간입니다. 욕실이나 주방 근처처럼 수증기가 많은 곳에 해당합니다.');
INSERT INTO environment_type (id, name, sunlight, ventilation, temperature, humidity, explanation) VALUES ('ENV-08', '통풍이 잘 되는 공간', '보통~높음'::sunlight_condition, '매우 높음'::ventilation_condition, '보통'::temperature_condition, '보통'::humidity_condition, '공기 순환이 좋은 개방된 공간입니다. 현관, 베란다 근처 등 바람이 잘 통하는 곳입니다.');
INSERT INTO environment_type (id, name, sunlight, ventilation, temperature, humidity, explanation) VALUES ('ENV-09', '밀폐된 공간', '낮음'::sunlight_condition, '매우 낮음'::ventilation_condition, '보통~높음'::temperature_condition, '보통~높음'::humidity_condition, '환기가 어렵고 공기 순환이 적은 공간입니다. 공기정화 효과가 좋은 식물이 추천됩니다.');
